def process_graph(graph_data):
    # Create a deep copy to avoid modifying the original graph
    graph_copy = copy.deepcopy(graph_data)

    # Identify the parent node (ju1.s1.dom) by its 'name' attribute or node id
    parent_id = None
    for nid, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s1.dom' or nid == 'ju1.s1.dom':
            parent_id = nid
            break

    # Add the new EK_PACKET_SWITCH node and connect it to the parent
    new_node_id = 'new_EK_PACKET_SWITCH_43'
    graph_copy.add_node(new_node_id, type=['EK_PACKET_SWITCH'])
    if parent_id is not None:
        graph_copy.add_edge(parent_id, new_node_id, type=['RK_CONTAINS'])

    # Helper function to recursively sum physical_capacity_bps of descendant PORT nodes
    def _sum_port_capacity(node_id):
        total = 0
        node_attrs = graph_copy.nodes[node_id]
        if 'EK_PORT' in node_attrs.get('type', []) and 'physical_capacity_bps' in node_attrs:
            total += node_attrs.get('physical_capacity_bps', 0)
        for _, succ, edata in graph_copy.out_edges(node_id, data=True):
            if 'RK_CONTAINS' in edata.get('type', []):
                total += _sum_port_capacity(succ)
        return total

    # Gather direct children of the parent and compute their total capacities
    child_capacity_list = []
    if parent_id is not None:
        for _, child_id, edata in graph_copy.out_edges(parent_id, data=True):
            if 'RK_CONTAINS' in edata.get('type', []):
                child_name = graph_copy.nodes[child_id].get('name', child_id)
                capacity = _sum_port_capacity(child_id)
                child_capacity_list.append((child_name, capacity))

    # Rank the children by total capacity (highest first)
    ranked_list = sorted(child_capacity_list, key=lambda x: x[1], reverse=True)

    # Convert the updated graph to JSON format
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    # Prepare the return object
    return_object = {
        'type': 'list',
        'data': ranked_list,
        'updated_graph': graph_json
    }
    return return_object

